import{_ as t,o as e,c as o,a2 as n}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6903_巨漢/20260502/F11_處分重大資產與資本配置_投資研究員.md","filePath":"審計報告庫/財務審計/6903_巨漢/20260502/F11_處分重大資產與資本配置_投資研究員.md"}'),r={name:"審計報告庫/財務審計/6903_巨漢/20260502/F11_處分重大資產與資本配置_投資研究員.md"};function i(l,a,_,s,d,h){return e(),o("div",null,[...a[0]||(a[0]=[n('<h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>近 3 年是否有處分重大資產？處分利益是否掩蓋本業獲利狀況？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>巨漢近 3 年無重大資產處分，僅例行設備汰換（年 &lt;500 萬）。獲利純粹來自本業工程收入，扣非後 EPS 與帳面 EPS 無差異，無任何一次性利益或業外操作之疑慮，獲利品質極高。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A（優）。無資產處分、無轉投資評價損益、無子公司減損，獲利結構單純乾淨。利空：資金運用極度保守，帳上現金 17-22 億僅做銀行定存，收益率 &lt;1%，資本配置效率低落，可能成為未來股東要求提高股利分配的壓力來源。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><ol><li><p><strong>處分資產檢視</strong>：現金流量表中「處分不動產、廠房及設備」每年金額低於 500 萬，屬例行性設備汰換，無重大資產出售。資產負債表中無待售資產或停業單位部門。</p></li><li><p><strong>業外收支穿透</strong>：業外收入幾乎全為利息收入（約 1,500-2,000 萬/年），無處分投資利益、無金融資產評價利益、無匯兌收益。業外支出同樣單純，無資產減損或轉投資損失。</p></li><li><p><strong>資本配置評析</strong>：公司無重大轉投資、無併購計畫、無海外設廠。所有盈餘幾乎全數以現金股利分配（配發率約 60-70%），剩餘現金留置帳上。無擴張性資本支出，成長完全依靠有機擴張。</p></li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>無處分資產的美化風險</strong>：這是正面訊號——公司不需要變賣資產來維持獲利，所有 EPS 都是真金白銀的工程收入。不應解讀為負面。</li><li><strong>資金運用效率的潛在利空</strong>：帳上現金 17-22 億（每股現金約 25-33 元），遠超過營運需求。若管理層無法提出有效的資金運用計畫，股東可能要求提高配息，屆時將限制公司未來成長的財務彈性。</li><li><strong>無轉投資的雙面刃</strong>：無轉投資雖避免了踩雷風險，但也代表公司缺乏開拓新成長曲線的能力。仰賴單一半導體廠務工程業務，若產業景氣反轉，獲利將面臨一次性衝擊。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>FinMind：TaiwanStockCashFlowsStatement（2023-2025 PropertyAndPlantAndEquipment）</li><li>FinMind：TaiwanStockFinancialStatements（TotalNonoperatingIncomeAndExpense）</li></ul>',12)])])}const u=t(r,[["render",i]]);export{p as __pageData,u as default};
